Reimplement timerEvent() to receive timer events. Prefer QTimer when signal-based scheduling is more convenient.

Previous workflow example retained from the original Qt pack:

```cpp
class Poller : public QObject
{
public:
    void startPolling() { timerId_ = startTimer(250); }
    void stopPolling()  { killTimer(timerId_); }

protected:
    void timerEvent(QTimerEvent *event) override
    {
        if (event->timerId() == timerId_)
            pollDevice();
    }

private:
    int timerId_ = 0;
};
```

QBasicTimer wraps a timer identifier and is appropriate for QObject subclasses implementing timerEvent().

Previous workflow example retained from the original Qt pack:

```cpp
class Blinker : public QWidget
{
    QBasicTimer timer_;

    void startBlink() { timer_.start(500, this); }

    void timerEvent(QTimerEvent *event) override
    {
        if (event->timerId() == timer_.timerId())
            update();
    }
};
```

