while (!ready_ && !deadline.hasExpired())
{
    condition_.wait(&mutex_, deadline);
}

// Timer callbacks are delivered by an event loop.
// Keep timeout handlers short: a busy event loop delays timer delivery.
// Requested precision is not a hard real-time guarantee.

