functions.insertText:
/*
 Use QLibrary when:
   - the DLL exposes plain C functions;
   - the DLL is not a Qt plugin;
   - you need a narrow ABI boundary with resolve().

 Use QPluginLoader when:
   - the DLL is a Qt plugin built with Q_PLUGIN_METADATA;
   - you want loader.instance() to return a QObject;
   - the host and plugin share a Qt interface contract.
*/

#include <QPluginLoader>
#include <QDebug>

QPluginLoader loader("plugins/mydriver");
QObject *object = loader.instance();
if (!object)
{
    qCritical() << loader.errorString();
    return;
}

auto *driver = qobject_cast<IDeviceDriver *>(object);
if (!driver)
{
    qCritical() << "Plugin does not implement IDeviceDriver";
    return;
}

driver->start();

QCameraPermission permission;
if (qApp->checkPermission(permission) == Qt::PermissionStatus::Undetermined)
{
    qApp->requestPermission(permission, this,
        [this](const QPermission &permission)
        {
            if (permission.status() == Qt::PermissionStatus::Granted)
                StartCamera();
        });
}

include(GNUInstallDirs)

install(TARGETS MyQtApp
    BUNDLE DESTINATION .
    RUNTIME DESTINATION ${CMAKE_INSTALL_BINDIR}
)

install(FILES "${CMAKE_CURRENT_SOURCE_DIR}/Scan_BLE_DLL.dll"
    DESTINATION ${CMAKE_INSTALL_BINDIR}
